makefile-examples.example:
test-prod:
  @echo "Checking Docker Compose services..."
  @python3 -c "import socket; s=socket.create_connection(('localhost',5000),2); s.close()" 2>/dev/null \
    || (echo "ERROR: MLflow not running. Run: docker compose up -d"; exit 1)
  @python3 -c "import socket; s=socket.create_connection(('localhost',9000),2); s.close()" 2>/dev/null \
    || (echo "ERROR: MinIO not running. Run: docker compose up -d"; exit 1)
  MINIVESS_ALLOW_HOST=1 uv run pytest tests/ -x -q \
    -m "not gpu_heavy and not requires_remote" \
    --ignore=tests/v2/quasi_e2e/ --ignore=tests/gpu_instance/ \
    --timeout=120

test-prod-remote:
  @echo "Checking remote infrastructure..."
  @sky check gcp || (echo "ERROR: SkyPilot GCP not configured"; exit 1)
  MINIVESS_ALLOW_HOST=1 uv run pytest tests/v2/cloud/ tests/ -x -q \
    -m "requires_remote" \
    --timeout=120

test-post-training:
  @echo "Checking mlruns/ for training results..."
  @test -d mlruns/ || (echo "ERROR: No mlruns/ directory. Run training first."; exit 1)
  MINIVESS_ALLOW_HOST=1 uv run pytest tests/ -x -q \
    -m "requires_mlruns" \
    --timeout=120
